import { rand } from "../utils.js";
export function sparkle(ok=true){const pool=ok?["✨","⭐","✅","💥"]:["💥","❌","⚡"];for(let i=0;i<9;i++){const el=document.createElement("div");el.className="sparkle";el.textContent=pool[rand(0,pool.length-1)];el.style.left=rand(12,88)+"vw";el.style.top=rand(18,70)+"vh";document.body.appendChild(el);setTimeout(()=>el.remove(),900)}}
export function drawLaser(targetId){const target=document.getElementById(targetId);if(!target)return;const rect=target.getBoundingClientRect(),x1=70,y1=window.innerHeight-95,x2=rect.left+rect.width/2,y2=rect.top+rect.height/2,length=Math.hypot(x2-x1,y2-y1),angle=Math.atan2(y2-y1,x2-x1)*180/Math.PI;const el=document.createElement("div");el.className="laser";el.style.left=x1+"px";el.style.top=y1+"px";el.style.width=length+"px";el.style.transform=`rotate(${angle}deg)`;document.body.appendChild(el);setTimeout(()=>el.remove(),320)}
